template.js_template:
(() => { 
                const root = {{DOM_CONTEXT}};
                const tickerWrap = root.querySelector('.ticker-wrap-v8');
                const dataEl = root.querySelector('#f-crawl-list');
                if(!tickerWrap || !dataEl) return;

                let subNewsList = [];
                try { subNewsList = JSON.parse(dataEl.innerHTML); } catch(e) { subNewsList = []; }
                if(subNewsList.length === 0) return;

                let content = "";
                subNewsList.forEach(news => {
                    content += '<span class="separator-v8">BTB INFO</span>';
                    content += '<span class="news-item-v8">' + news + '</span>';
                });
                tickerWrap.innerHTML = content + content;
            })();
